const msgs = [
  "🔮 正在為你抽牌中…",
  "🃏 洗牌中，命運正在轉動…",
  "✨ 請稍等，靈感正在連線中…"
];
const pick = msgs[Math.floor(Math.random() * msgs.length)];

return {
  to: $input.first().json.userId ,
  messages: [{ type: "text", text: pick }]
};

// 把 LINE webhook 的 events[] 拆成多筆 item，讓後續每筆獨立處理
const out = [];
const events = $json.events || $json.body?.events || [];

for (const ev of events) {
  const base = {
    replyToken: ev.replyToken || null,
    userId: ev.source?.userId || null,
    groupId: ev.source?.groupId || null,
    roomId: ev.source?.roomId || null,
    eventType: ev.type,
    timestamp: ev.timestamp,
    tsISO: ev.timestamp ? new Date(ev.timestamp).toISOString() : null,
  };

  if (ev.type === 'message' && ev.message?.type === 'text') {
    // 🔹 使用者發文字訊息（例如「抽牌」）
    out.push({
      json: {
        ...base,
        messageType: ev.message.type,
        userText: ev.message.text,
        quoteToken: ev.message?.quoteToken || null,
      }
    });

  } else if (ev.type === 'postback') {
    // 🔹 使用者按了 postback 按鈕（例如抽牌選項）
    out.push({
      json: {
        ...base,
        postbackData: ev.postback?.data || null,
        params: ev.postback?.params || null,
      }
    });

  } else if (ev.type === 'follow' || ev.type === 'join') {
    // 🔹 新加入好友或被邀進群
    out.push({
      json: {
        ...base,
        notice: ev.type === 'follow' ? 'new_friend' : 'join_group'
      }
    });

  } else {
    // 🔹 其他未分類事件（可用來 debug）
    out.push({
      json: {
        ...base,
        raw: ev
      }
    });
  }
}

// 若無事件則回傳一筆 skip item，避免後續節點報錯
return out.length ? out : [{ json: { skip: true } }];

