// 將每一頁的所有圖片「展平」成多筆，每筆只帶一張圖，並把 binary key 統一改名為 'file'

function safeName(s) {
  return (s || 'untitled').replace(/[^\w\u4e00-\u9fa5-]+/g, '_').slice(0, 40);
}
function extFromName(name, fallback='jpg') {
  const m = (name||'').toLowerCase().match(/\.(jpe?g|png|webp|gif)$/);
  return (m ? m[1] : fallback).replace('jpeg','jpg');
}
// 台灣時間（UTC+8）
const taiwanNow = new Date().toLocaleString('sv-SE', { timeZone: 'Asia/Taipei' });

// 格式化成檔名友善版本（例：2025-10-07_17-45-32）
const dateStr = taiwanNow.replace(' ', '_').replace(/:/g, '-');

const out = [];

for (const it of items) {
  const page = it.json || {};
  const p = page.properties || {};
  const title = (p['名稱']?.title?.[0]?.plain_text) || (p['Title']?.title?.[0]?.plain_text) || 'untitled';
  const safe = safeName(title);

  // Notion 檔案欄位（你是「照片」，若叫 Image 也一併兼容）
  const files = (p['圖片']?.files || p['Image']?.files || []);

  // 這筆 item 裡 Notion Download Files 產生的所有 binary key（通常會是 照片_0、照片_1…）
  const binKeys = Object.keys(it.binary || {});
  if (!binKeys.length) continue;

  // 若數量對得上，就一一對應；對不上就以 binary 為主逐一輸出
  const n = Math.max(files.length, binKeys.length);

  for (let i = 0; i < n; i++) {
    const binKey = binKeys[i] ?? binKeys[0];     // 若只有一個 key（你碰到全叫 照片_0），就用同一個 key 但逐筆輸出
    const binObj = it.binary?.[binKey];
    if (!binObj) continue;

    const originalName = files[i]?.name || binObj.fileName || `image_${i}.jpg`;
    const ext = extFromName(originalName);
    const basePath = $env.Img_R2_Path || 'divination';
    const key = `${basePath}/${safe}_${dateStr}_${Math.random().toString(36).slice(2,6)}.${ext}`;
    const url = files[i].file.url;

    // ★ 重點：把 binary 重新命名為 'file'，每筆只帶「單一」binary
    const binaryOut = { file: binObj };

    out.push({
      json: {
        pageId: page.id,
        title,
        index: i,
        key,           // 上傳到 R2 的物件 key（Worker 的 form-data "key" 就填這個）
        binProp: 'file',// 之後要用 Binary Property 時固定就是 'file'
        url: url
      },
      binary: binaryOut
    });
  }
}

return out;

// Function (Run once for all items)

const NORMALIZE_ID = true; // true = 去掉 Notion pageId 的 "-"，要跟 /getCardId 端一致

function mapDeck(name) {
  const n = String(name || '').trim().toLowerCase();
  if (n === '感情' || n === 'love')   return 'love';
  if (n === '財運' || n === 'money')  return 'money';
  if (n === '事業' || n === 'career') return 'career';
  if (n === '今日' || n === 'daily')  return 'daily';
  return null;
}

const groups = { love: [], money: [], career: [], daily: [] };

for (const it of items) {
  const page = it.json || {};
  const idRaw = page.id || page.pageId || '';
  if (!idRaw) continue;

  const id = NORMALIZE_ID ? idRaw.replace(/-/g, '') : idRaw;

  // 取分類（你也可改抓 'deck' 欄位）
  const catName =
    page.properties?.['分類']?.select?.name ||
    page.properties?.['deck']?.select?.name ||
    '';

  const deck = mapDeck(catName);
  if (!deck) continue;

  groups[deck].push(id);
}

// 依牌庫輸出多筆 items，方便後面直接一筆一 POST
const out = Object.entries(groups)
  .filter(([, ids]) => ids.length > 0)
  .map(([deck, ids]) => ({ json: { deck, ids } }));

return out.length ? out : [{ json: { deck: null, ids: [] } }];

