const data = $json.body ?? $json;

// 保留原本上游的欄位（例如 replyToken、userId、deck 等）
let result = {
  ...$json,  // ← 把原本的 JSON 整個帶過來
  ok: data.ok ?? false,
  used: data.used ?? null,
  deck: data.deck ?? $json.deck ?? null,
  ids: data.ids ?? [],
};

// 只判斷是否有抽到牌（ids 是否為空陣列）
if (Array.isArray(result.ids) && result.ids.length > 0) {
  result.status = "success"; // 抽到牌
} else {
  result.status = "empty"; // 沒抽到牌（可能今天抽過 or 出錯）
}

return [{ json: result }];
